// Mapping of text patterns to their SVG string replacements for HTML injection
const nowrap = (svg: string, text: string) => `<span style="white-space:nowrap">${svg} ${text}</span>`;
const htmlReplacements: [RegExp, string][] = [
  [/\bReact Native\b/, nowrap(logoSvgStrings.react, 'React Native')],
  [/\bReact\b(?! Native)/, nowrap(logoSvgStrings.react, 'React')],
  [/\bNext\.js\b/, nowrap(logoSvgStrings.nextjs, 'Next.js')],
  [/\bTailwind CSS\b/, nowrap(logoSvgStrings.tailwind, 'Tailwind CSS')],
  [/\bGoogle Cloud Platform\b/, nowrap(logoSvgStrings.gcp, 'Google Cloud Platform')],
];

export function logoifyHtml(html: string): string {
  let result = html;
  for (const [pattern, replacement] of htmlReplacements) {
    result = result.replace(pattern, replacement);
  }
  return result;
}

